"use client";

import { useEffect, useRef, useState } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

const PHASES = [
  { ko: "들이쉬세요", en: "breathe in" },
  { ko: "머금으세요", en: "hold" },
  { ko: "내쉬세요", en: "breathe out" },
] as const;

const PHASE_MS = 4000;
const CYCLE_MS = PHASE_MS * 3;

/**
 * 03 — a usable 4·4·4 breathing guide. One rAF clock drives both the orb
 * (a `--sup-breath` scale variable, half-sine eased) and the phase/count
 * text, so they can never drift apart. The instruction itself never
 * depends on the motion: a plain written sentence above the orb carries
 * the whole exercise, the animated readout is aria-hidden decoration on
 * top of it, and under reduced motion the orb holds still while the
 * text-only count remains available behind the same button.
 */
export default function BreathingGuide() {
  const reduced = usePrefersReducedMotion();
  const stageRef = useRef<HTMLDivElement | null>(null);
  /** Where in the 12s cycle we paused, so resuming never snaps. */
  const offsetRef = useRef(0);
  /**
   * The visitor's explicit choice, if any. Until they press the button the
   * guide follows the OS: already breathing for motion users, resting (a
   * text-only count away) for reduced-motion users.
   */
  const [choice, setChoice] = useState<boolean | null>(null);
  const [phase, setPhase] = useState(0);
  const [count, setCount] = useState(4);
  const running = choice ?? !reduced;

  useEffect(() => {
    const stage = stageRef.current;
    if (!stage || !running) return;

    let raf = 0;
    let on = false;
    let inView = true;
    let anchor = 0;
    let lastPhase = -1;
    let lastCount = -1;
    const easeSine = (u: number) => 0.5 - 0.5 * Math.cos(Math.PI * u);

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      const t = (now - anchor) % CYCLE_MS;
      offsetRef.current = t;
      const p = Math.floor(t / PHASE_MS);
      const u = (t % PHASE_MS) / PHASE_MS;
      const c = 4 - Math.floor(u * 4);
      if (p !== lastPhase) {
        lastPhase = p;
        setPhase(p);
      }
      if (c !== lastCount) {
        lastCount = c;
        setCount(c);
      }
      if (!reduced) {
        const v = p === 0 ? easeSine(u) : p === 1 ? 1 : 1 - easeSine(u);
        stage.style.setProperty("--sup-breath", v.toFixed(4));
      }
    };

    const start = () => {
      if (on) return;
      on = true;
      anchor = performance.now() - offsetRef.current;
      raf = requestAnimationFrame(step);
    };
    const stop = () => {
      on = false;
      cancelAnimationFrame(raf);
    };

    const io = new IntersectionObserver((hits) => {
      inView = hits[hits.length - 1].isIntersecting;
      if (inView && !document.hidden) start();
      else stop();
    });
    io.observe(stage);

    const onVisibility = () => {
      if (document.hidden) stop();
      else if (inView) start();
    };
    document.addEventListener("visibilitychange", onVisibility);

    return () => {
      stop();
      io.disconnect();
      document.removeEventListener("visibilitychange", onVisibility);
    };
  }, [running, reduced]);

  return (
    <section id="sup-breath" className="sup-breath" aria-labelledby="sup-breath-title">
      <div className="sup-sec" data-reveal>
        <span className="sup-sec__no" lang="ko" aria-hidden="true">
          둘
        </span>
        <h2 className="sup-sec__title" id="sup-breath-title">
          one breath{" "}
          <span lang="ko" className="sup-sec__ko">
            숨
          </span>
        </h2>
      </div>

      <p className="sup-breath__how" data-reveal>
        <em>In for four, hold for four, out for four — the forest counts with you.</em>
        <span lang="ko">
          넷을 세며 들이쉬고, 넷을 머금고, 넷을 세며 내쉬세요. 숲이 함께 세어
          줍니다.
        </span>
      </p>

      <div ref={stageRef} className="sup-breath__stage" data-reveal>
        <div className="sup-breath__halo" aria-hidden="true" />
        <div className="sup-breath__orb" aria-hidden="true" />
        <div className="sup-breath__readout" aria-hidden="true">
          {running ? (
            <>
              <span lang="ko" className="sup-breath__word">
                {PHASES[phase].ko}
              </span>
              <span className="sup-breath__word-en">{PHASES[phase].en}</span>
              <span className="sup-breath__count">{count}</span>
            </>
          ) : (
            <>
              <span lang="ko" className="sup-breath__word">
                쉬는 중
              </span>
              <span className="sup-breath__word-en">resting</span>
              <span className="sup-breath__count">·</span>
            </>
          )}
        </div>
      </div>

      <button
        type="button"
        className="sup-breath__toggle"
        aria-pressed={running}
        onClick={() => setChoice(!running)}
      >
        {running ? (
          <>
            <span lang="ko">잠시 멈춤</span> · rest the count
          </>
        ) : (
          <>
            <span lang="ko">숨 세기 시작</span> · start the count
          </>
        )}
      </button>

      <p className="sup-breath__note" data-reveal>
        <em>There is no correct way to breathe here.</em>{" "}
        <span lang="ko">여기서는 숨에 정답이 없습니다.</span>
      </p>
    </section>
  );
}

"use client";

import type { CSSProperties } from "react";
import { growPlant, leafPath, type Plant } from "./plant";
import { useGrowth } from "../hooks/useGrowth";
import { usePointerDrift } from "../hooks/usePointerDrift";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

/**
 * Generated once at module load with fixed seeds — identical markup on the
 * server and the client, so the plants are real SSR'd content.
 * MAIN is the hero tree (5 L-system iterations); BACK is the smaller
 * understory shrub that drifts the other way under the pointer.
 */
const MAIN = growPlant(20260710, 5, 560, 720, 0.62);
const BACK = growPlant(1207, 3, 560, 720, 0.9);

function PlantSvg({ plant, className }: { plant: Plant; className: string }) {
  return (
    <svg
      className={className}
      viewBox={plant.viewBox}
      preserveAspectRatio="xMidYMax meet"
      aria-hidden="true"
      focusable="false"
    >
      <g className="sup-growth">
        {plant.branches.map((b, i) => (
          <path
            key={`b${i}`}
            className={`sup-growth__branch sup-growth__branch--t${Math.min(b.depth, 3)}`}
            d={b.d}
            pathLength={1}
            strokeWidth={b.w}
            style={
              {
                "--t1": b.t1,
                "--tw": Math.round((b.t1 - b.t0) * 1000) / 1000,
              } as CSSProperties
            }
          />
        ))}
        {plant.leaves.map((l, i) => (
          <g key={`l${i}`} transform={`translate(${l.x} ${l.y}) rotate(${l.ang})`}>
            <path
              className={`sup-growth__leaf sup-growth__leaf--${l.tone}`}
              d={leafPath(l.size)}
              style={{ "--lt": l.t } as CSSProperties}
            />
          </g>
        ))}
      </g>
    </svg>
  );
}

/**
 * The arrival. A cream clearing where an L-system tree draws itself in as
 * you settle — stroke-dashoffset windows staggered along the plant's own
 * growth clock — while the title simply waits. Without JavaScript, or under
 * reduced motion, both plants stand fully grown from the first paint.
 */
export default function Hero() {
  const reduced = usePrefersReducedMotion();
  const driftRef = usePointerDrift<HTMLElement>(reduced);
  const growRef = useGrowth<HTMLDivElement>(reduced);

  return (
    <header id="sup-hero" ref={driftRef} className="sup-hero">
      <div className="sup-hero__sun" aria-hidden="true" />

      <div ref={growRef} className="sup-hero__stage" aria-hidden="true">
        <PlantSvg plant={BACK} className="sup-hero__plant sup-hero__plant--back" />
        <PlantSvg plant={MAIN} className="sup-hero__plant sup-hero__plant--main" />
      </div>

      <div className="sup-hero__copy">
        <p className="sup-hero__kicker">
          FOREST BATHING <span aria-hidden="true">·</span>{" "}
          <span lang="ko">산림욕 리트릿</span>
        </p>
        <h1 className="sup-hero__title">
          <span lang="ko" className="sup-hero__hangul">
            숲
          </span>
          <span className="sup-hero__latin">
            SUP<span className="sup-hero__latin-sub">the forest, plainly</span>
          </span>
        </h1>
        <p className="sup-hero__lede">
          <em>Breathe in for four. The forest is already breathing with you.</em>
          <span lang="ko">
            넷을 세며 들이쉬세요. 숲은 이미 당신과 함께 숨 쉬고 있습니다.
          </span>
        </p>
        <a className="sup-hero__cta" href="#sup-breath">
          숨 고르러 가기 <span aria-hidden="true">·</span> begin with one breath
        </a>
      </div>

      <p className="sup-hero__hint">
        <span lang="ko">천천히 내려오세요</span> — nothing here is in a hurry
      </p>
    </header>
  );
}

/**
 * Deterministic L-system plant generator.
 *
 * Runs at module load on both the server and the client with a fixed seed,
 * so the SVG markup is byte-identical across hydration — the plant is real
 * server-rendered content, not a client effect.
 *
 * Grammar (a classic bracketed L-system):
 *   axiom  X
 *   rules  X → F[+X][-X]FX      (a bud becomes: grow, branch left, branch
 *          F → FF                right, grow again, keep a leading bud)
 *
 * The turtle interpretation adds what the grammar can't say: per-segment
 * angle wander (nothing alive is straight), mild phototropism pulling every
 * heading back toward "up", shrinking step lengths with branch depth, and a
 * growth clock — each branch records how far along the plant's total reach
 * it starts and ends, which styles.css turns into a stroke-dashoffset
 * drawing window. Base grows first, crown grows last, exactly like a plant.
 */

export type PlantBranch = {
  /** SVG path data (midpoint-smoothed quadratics through the turtle walk). */
  d: string;
  /** Stroke width in final viewBox units — thick at the root, hairline at tips. */
  w: number;
  /** Growth window start, 0..1 along the whole plant's growth clock. */
  t0: number;
  /** Growth window end. */
  t1: number;
  /** Branch depth (bracket nesting), for stroke color tiers. */
  depth: number;
};

export type PlantLeaf = {
  x: number;
  y: number;
  /** Rotation in degrees — roughly the heading of the twig it sits on. */
  ang: number;
  /** Leaf length in final viewBox units. */
  size: number;
  /** Moment on the growth clock when this leaf unfurls. */
  t: number;
  /** Alternating foliage tone (0 = lichen, 1 = deep moss). */
  tone: 0 | 1;
};

export type Plant = {
  branches: PlantBranch[];
  leaves: PlantLeaf[];
  viewBox: string;
};

/** mulberry32 — tiny seeded PRNG; growth must be identical on server and client. */
export function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

function rewrite(axiom: string, rules: Record<string, string>, n: number): string {
  let s = axiom;
  for (let i = 0; i < n; i++) {
    let next = "";
    for (const ch of s) next += rules[ch] ?? ch;
    s = next;
  }
  return s;
}

type Frame = {
  x: number;
  y: number;
  ang: number;
  depth: number;
  /** Cumulative growth distance from the seed along this lineage. */
  dist: number;
  startDist: number;
  pts: number[];
};

type RawBranch = { pts: number[]; startDist: number; endDist: number; depth: number };
type RawLeaf = { x: number; y: number; ang: number; dist: number; depth: number; jit: number; tone: 0 | 1 };

const BRANCH_ANGLE = 27;

/**
 * Grow a plant into a `boxW × boxH` viewBox. The root sits on the bottom
 * edge; the whole silhouette is normalized to fit with a small margin, so
 * the same code yields the hero tree (4 iterations) and the smaller
 * understory shrub (3 iterations) without hand-tuned step lengths.
 */
export function growPlant(
  seed: number,
  iterations: number,
  boxW: number,
  boxH: number,
  leafChance = 0.82,
): Plant {
  const rnd = mulberry32(seed);
  const sentence = rewrite("X", { X: "F[+X][-X]FX", F: "FF" }, iterations);

  const rawBranches: RawBranch[] = [];
  const rawLeaves: RawLeaf[] = [];
  const stack: Frame[] = [];
  let f: Frame = { x: 0, y: 0, ang: -90, depth: 0, dist: 0, startDist: 0, pts: [0, 0] };

  for (const ch of sentence) {
    if (ch === "F") {
      const step = 10 * Math.pow(0.92, f.depth) * (0.85 + rnd() * 0.3);
      f.ang += (rnd() - 0.5) * 8; // wander — nothing alive is straight
      f.ang += (-90 - f.ang) * 0.034; // phototropism — lean back toward the light
      const r = (f.ang * Math.PI) / 180;
      f.x += Math.cos(r) * step;
      f.y += Math.sin(r) * step;
      f.dist += step;
      f.pts.push(f.x, f.y);
    } else if (ch === "+") {
      f.ang += BRANCH_ANGLE + (rnd() - 0.5) * 10;
    } else if (ch === "-") {
      f.ang -= BRANCH_ANGLE + (rnd() - 0.5) * 10;
    } else if (ch === "[") {
      stack.push(f);
      f = {
        x: f.x,
        y: f.y,
        ang: f.ang,
        depth: f.depth + 1,
        dist: f.dist,
        startDist: f.dist,
        pts: [f.x, f.y],
      };
    } else if (ch === "]") {
      if (f.pts.length >= 4) {
        rawBranches.push({
          pts: f.pts,
          startDist: f.startDist,
          endDist: f.dist,
          depth: f.depth,
        });
      }
      const parent = stack.pop();
      if (parent) f = parent;
    } else if (ch === "X" && rnd() < leafChance) {
      // a bud that never became a branch — a leaf lives here
      rawLeaves.push({
        x: f.x,
        y: f.y,
        ang: f.ang + (rnd() - 0.5) * 70,
        dist: f.dist,
        depth: f.depth,
        jit: rnd(),
        tone: rnd() < 0.45 ? 1 : 0,
      });
    }
  }
  // the trunk itself — the frame that never got popped
  rawBranches.push({ pts: f.pts, startDist: 0, endDist: f.dist, depth: 0 });

  // ---- normalize into the requested viewBox ------------------------------
  let minX = Infinity;
  let maxX = -Infinity;
  let minY = Infinity;
  let maxY = -Infinity;
  for (const b of rawBranches) {
    for (let i = 0; i < b.pts.length; i += 2) {
      if (b.pts[i] < minX) minX = b.pts[i];
      if (b.pts[i] > maxX) maxX = b.pts[i];
      if (b.pts[i + 1] < minY) minY = b.pts[i + 1];
      if (b.pts[i + 1] > maxY) maxY = b.pts[i + 1];
    }
  }
  const margin = boxW * 0.06;
  const s = Math.min(
    (boxW - margin * 2) / Math.max(maxX - minX, 1),
    (boxH - margin) / Math.max(maxY - minY, 1),
  );
  // center horizontally; the seed (raw y = 0, the lowest point) sits on the ground
  const ox = boxW / 2 - ((minX + maxX) / 2) * s;
  const oy = boxH - 2 - maxY * s;
  const px = (x: number) => Math.round((x * s + ox) * 10) / 10;
  const py = (y: number) => Math.round((y * s + oy) * 10) / 10;

  let maxDist = 0;
  for (const b of rawBranches) if (b.endDist > maxDist) maxDist = b.endDist;
  for (const l of rawLeaves) if (l.dist > maxDist) maxDist = l.dist;
  /** Map a growth distance onto the shared 0..1 clock (crown done by ~0.93). */
  const clock = (d: number) => 0.02 + 0.9 * (d / maxDist);

  const branches: PlantBranch[] = rawBranches.map((b) => {
    // midpoint smoothing: pass through the endpooints, curve near the interior
    const n = b.pts.length / 2;
    const X = (i: number) => px(b.pts[i * 2]);
    const Y = (i: number) => py(b.pts[i * 2 + 1]);
    let d = `M${X(0)} ${Y(0)}`;
    if (n === 2) {
      d += `L${X(1)} ${Y(1)}`;
    } else {
      for (let i = 1; i < n - 1; i++) {
        const mx = Math.round(((X(i) + X(i + 1)) / 2) * 10) / 10;
        const my = Math.round(((Y(i) + Y(i + 1)) / 2) * 10) / 10;
        d += `Q${X(i)} ${Y(i)} ${mx} ${my}`;
      }
      d += `L${X(n - 1)} ${Y(n - 1)}`;
    }
    const t0 = clock(b.startDist);
    const t1 = Math.max(t0 + 0.03, clock(b.endDist));
    return {
      d,
      w: Math.max(0.9, 4.8 * Math.pow(0.68, b.depth)),
      t0: Math.round(t0 * 1000) / 1000,
      t1: Math.round(t1 * 1000) / 1000,
      depth: b.depth,
    };
  });

  const leaves: PlantLeaf[] = rawLeaves.map((l) => ({
    x: px(l.x),
    y: py(l.y),
    ang: Math.round(l.ang * 10) / 10,
    size: Math.round(Math.min(44, Math.max(20, s * 8 * Math.pow(0.96, l.depth) * (0.7 + l.jit * 0.7))) * 10) / 10,
    t: Math.round(Math.min(0.93, clock(l.dist)) * 1000) / 1000,
    tone: l.tone,
  }));

  return { branches, leaves, viewBox: `0 0 ${boxW} ${boxH}` };
}

/** Almond-shaped leaf path of length `size`, base at the local origin. */
export function leafPath(size: number): string {
  const half = Math.round(size * 0.3 * 10) / 10;
  const mid = Math.round(size * 0.42 * 10) / 10;
  return `M0 0Q${mid} ${-half} ${size} 0Q${mid} ${half} 0 0Z`;
}

"use client";

import { useEffect, useRef } from "react";
import { mulberry32 } from "./plant";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

/** Backing-store resolution cap. */
const MAX_DPR = 2;
/** Throttle: skip frames that arrive faster than ~64fps (144Hz displays). */
const FRAME_MS = 15.5;
/** Resolution of the 1-D wind field the pointer writes into. */
const WIND_N = 96;
/** How far the wind spreads sideways per frame (diffusion). */
const WIND_SPREAD = 0.22;
/** How quickly a gust is forgotten per frame. */
const WIND_DECAY = 0.945;
/** Static timestamp for the reduced-motion frame — a mid-gust that composes well. */
const STILL_T = 8.4;

type Blade = {
  x: number;
  y: number;
  h: number;
  /** Resting lean — no blade stands at attention. */
  lean: number;
  /** How much of the ambient breeze this blade feels. */
  sway: number;
  stiff: number;
  damp: number;
  bend: number;
  vel: number;
};

type Band = {
  blades: Blade[][];
  widths: number;
  tones: [string, string];
};

/** The ambient breeze: three unrelated sine drifts plus a traveling gust. */
function ambient(nx: number, ts: number): number {
  const base =
    0.2 * Math.sin(nx * 2.4 + ts * 0.5) +
    0.11 * Math.sin(nx * 5.9 - ts * 0.31) +
    0.06 * Math.sin(nx * 13 + ts * 0.83);
  const gc = ((ts * 0.041) % 1.6) - 0.3;
  const ge = Math.exp(-(((nx - gc) / 0.15) ** 2));
  const gs = Math.max(0, Math.sin(ts * 0.19 + 1.2)) * 0.55;
  return base + ge * gs;
}

/**
 * 02 — the signature moment. A canvas meadow of ~450 instanced grass blades,
 * each one a quadratic curve with its own spring. Moving the pointer writes
 * a velocity impulse into a 1-D wind field that diffuses and decays, so a
 * flick of the hand sends a visible breeze traveling across the grass, and
 * every blade bends and recovers on its own spring constant. On touch, or
 * with no pointer at all, an autonomous gust cycle keeps the field alive.
 * Reduced motion renders one composed mid-breeze frame and stops.
 */
export default function WindField() {
  const stageRef = useRef<HTMLDivElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const reduced = usePrefersReducedMotion();

  useEffect(() => {
    const stage = stageRef.current;
    const canvas = canvasRef.current;
    if (!stage || !canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const style = getComputedStyle(canvas);
    const token = (name: string, fallback: string) =>
      style.getPropertyValue(name).trim() || fallback;
    const lit = token("--sup-grass-lit", "#c9d2ab");
    const back = token("--sup-grass-back", "#a8b89a");
    const mid = token("--sup-grass-mid", "#7d9465");
    const front = token("--sup-grass-front", "#55693f");
    const pollenTone = token("--sup-pollen", "#d9cd8f");

    let W = 0;
    let H = 0;
    let raf = 0;
    let running = false;
    let last = 0;
    let t = reduced ? STILL_T * 1000 : 0;

    const wind = new Float32Array(WIND_N);
    const windTmp = new Float32Array(WIND_N);
    const windAt = (nx: number): number => {
      const f = Math.min(Math.max(nx, 0), 0.9999) * (WIND_N - 1);
      const i = f | 0;
      const u = f - i;
      return wind[i] * (1 - u) + wind[i + 1] * u;
    };

    /** Two tone groups per band so a frame costs six strokeStyle changes. */
    const bands: Band[] = [
      { blades: [[], []], widths: 1.1, tones: [back, lit] },
      { blades: [[], []], widths: 1.5, tones: [mid, back] },
      { blades: [[], []], widths: 2.1, tones: [front, mid] },
    ];
    const pollen: { x: number; y: number; r: number; ph: number }[] = [];

    const build = () => {
      const rnd = mulberry32(1207);
      const rect = stage.getBoundingClientRect();
      const dpr = Math.min(window.devicePixelRatio || 1, MAX_DPR);
      W = rect.width;
      H = rect.height;
      canvas.width = Math.round(W * dpr);
      canvas.height = Math.round(H * dpr);
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.lineCap = "round";

      const spec = [
        { n: W / 6, y0: 0.78, y1: 0.87, h0: 0.16, h1: 0.28 },
        { n: W / 8, y0: 0.87, y1: 0.94, h0: 0.24, h1: 0.4 },
        { n: W / 13, y0: 0.95, y1: 1.02, h0: 0.34, h1: 0.56 },
      ];
      // Blades are born already posed in the current breeze, so the first
      // frame (and the only frame, under reduced motion) is composed.
      const ts0 = t * 0.001;
      for (let b = 0; b < 3; b++) {
        bands[b].blades[0].length = 0;
        bands[b].blades[1].length = 0;
        const s = spec[b];
        const count = Math.max(24, Math.round(s.n));
        for (let i = 0; i < count; i++) {
          const x = ((i + rnd()) / count) * (W + 20) - 10;
          const sway = 0.75 + rnd() * 0.5;
          const blade: Blade = {
            x,
            y: (s.y0 + rnd() * (s.y1 - s.y0)) * H,
            h: (s.h0 + rnd() * (s.h1 - s.h0)) * H,
            lean: (rnd() - 0.5) * 0.3,
            sway,
            stiff: 0.03 + rnd() * 0.03,
            damp: 0.88 + rnd() * 0.05,
            bend: ambient(x / W, ts0) * sway,
            vel: 0,
          };
          bands[b].blades[rnd() < 0.24 ? 1 : 0].push(blade);
        }
      }

      pollen.length = 0;
      for (let i = 0; i < 22; i++) {
        pollen.push({
          x: rnd(),
          y: 0.3 + rnd() * 0.45,
          r: 0.8 + rnd() * 1.3,
          ph: rnd() * Math.PI * 2,
        });
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, W, H);
      const ts = t * 0.001;

      ctx.globalAlpha = 0.55;
      ctx.fillStyle = pollenTone;
      for (const p of pollen) {
        const px = ((p.x + ts * (0.005 + p.r * 0.002)) % 1.04) - 0.02;
        const py = p.y + Math.sin(ts * 0.4 + p.ph) * 0.018;
        ctx.beginPath();
        ctx.arc(px * W, py * H, p.r, 0, Math.PI * 2);
        ctx.fill();
      }
      ctx.globalAlpha = 1;

      for (const band of bands) {
        for (let g = 0; g < 2; g++) {
          const blades = band.blades[g];
          if (blades.length === 0) continue;
          ctx.beginPath();
          for (const bl of blades) {
            const bend = bl.bend + bl.lean;
            const tipX = bl.x + bend * bl.h * 0.62;
            const tipY = bl.y - bl.h * (1 - Math.abs(bend) * 0.22);
            ctx.moveTo(bl.x, bl.y);
            ctx.quadraticCurveTo(
              bl.x + bend * bl.h * 0.08,
              bl.y - bl.h * 0.55,
              tipX,
              tipY,
            );
          }
          ctx.strokeStyle = band.tones[g];
          ctx.lineWidth = band.widths;
          ctx.stroke();
        }
      }
    };

    const settle = (k: number) => {
      // wind field: diffuse sideways, then decay toward calm
      for (let i = 0; i < WIND_N; i++) {
        const l = wind[Math.max(0, i - 1)];
        const r = wind[Math.min(WIND_N - 1, i + 1)];
        windTmp[i] = wind[i] + (l + r - 2 * wind[i]) * WIND_SPREAD * k;
      }
      const decay = Math.pow(WIND_DECAY, k);
      for (let i = 0; i < WIND_N; i++) wind[i] = windTmp[i] * decay;

      const ts = t * 0.001;
      for (let b = 0; b < 3; b++) {
        const reach = 1.15 - b * 0.18; // the near rows feel the pointer most
        for (const group of bands[b].blades) {
          for (const bl of group) {
            const nx = bl.x / W;
            const target =
              ambient(nx, ts) * bl.sway + windAt(nx) * reach * bl.sway;
            bl.vel += (target - bl.bend) * bl.stiff * k;
            bl.vel *= Math.pow(bl.damp, k);
            bl.bend += bl.vel * k;
            if (bl.bend > 1.4) bl.bend = 1.4;
            else if (bl.bend < -1.4) bl.bend = -1.4;
          }
        }
      }
    };

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      if (now - last < FRAME_MS) return;
      const dt = Math.min(now - last, 48);
      last = now;
      t += dt;
      settle(dt / 16.7);
      draw();
    };

    const start = () => {
      if (running || reduced) return;
      running = true;
      last = performance.now();
      raf = requestAnimationFrame(step);
    };
    const stop = () => {
      running = false;
      cancelAnimationFrame(raf);
    };

    /** A pass of the hand writes its horizontal velocity into the wind. */
    let lastPX = -1;
    let lastPT = 0;
    const deposit = (nx: number, v: number) => {
      const c = nx * WIND_N;
      const from = Math.max(0, Math.floor(c - 7));
      const to = Math.min(WIND_N - 1, Math.ceil(c + 7));
      for (let i = from; i <= to; i++) {
        wind[i] += v * Math.exp(-(((i - c) / 3.2) ** 2)) * 0.5;
      }
    };
    const onPointerMove = (ev: PointerEvent) => {
      const rect = stage.getBoundingClientRect();
      const now = performance.now();
      if (lastPX >= 0 && now - lastPT < 120) {
        const v = Math.max(
          -2.4,
          Math.min(2.4, (ev.clientX - lastPX) / Math.max(now - lastPT, 8)),
        );
        deposit((ev.clientX - rect.left) / rect.width, v * 1.4);
      }
      lastPX = ev.clientX;
      lastPT = now;
    };
    const onPointerLeave = () => {
      lastPX = -1;
    };
    const onPointerDown = (ev: PointerEvent) => {
      // a touch (or press) parts the grass outward from the fingertip
      const rect = stage.getBoundingClientRect();
      const c = ((ev.clientX - rect.left) / rect.width) * WIND_N;
      for (let i = 0; i < WIND_N; i++) {
        const d = (i - c) / 4;
        wind[i] += Math.sign(d) * Math.exp(-d * d) * 0.9;
      }
    };

    build();
    if (reduced) {
      // one composed frame: a mid-gust, blades resting where the breeze holds them
      draw();
    } else {
      stage.addEventListener("pointermove", onPointerMove);
      stage.addEventListener("pointerleave", onPointerLeave);
      stage.addEventListener("pointerdown", onPointerDown);
    }

    let inView = false;
    const io = new IntersectionObserver(
      (hits) => {
        inView = hits[hits.length - 1].isIntersecting;
        if (inView && !document.hidden) start();
        else stop();
      },
      { rootMargin: "120px 0px" },
    );
    io.observe(stage);

    const onVisibility = () => {
      if (document.hidden) stop();
      else if (inView) start();
    };
    document.addEventListener("visibilitychange", onVisibility);

    const ro = new ResizeObserver(() => {
      build();
      if (!running) draw();
    });
    ro.observe(stage);

    return () => {
      stop();
      io.disconnect();
      ro.disconnect();
      document.removeEventListener("visibilitychange", onVisibility);
      stage.removeEventListener("pointermove", onPointerMove);
      stage.removeEventListener("pointerleave", onPointerLeave);
      stage.removeEventListener("pointerdown", onPointerDown);
    };
  }, [reduced]);

  return (
    <section className="sup-wind" aria-labelledby="sup-wind-title">
      <div className="sup-sec" data-reveal>
        <span className="sup-sec__no" lang="ko" aria-hidden="true">
          하나
        </span>
        <h2 className="sup-sec__title" id="sup-wind-title">
          the wind field{" "}
          <span lang="ko" className="sup-sec__ko">
            바람의 들
          </span>
        </h2>
      </div>

      <p className="sup-wind__lede" data-reveal>
        <em>Wind you can see — we call it grass.</em>{" "}
        <span lang="ko">눈에 보이는 바람을, 우리는 풀이라고 부릅니다.</span>
      </p>

      <div
        ref={stageRef}
        className="sup-wind__stage"
        role="img"
        aria-label="A meadow of drawn grass blades bending under a breeze that follows your hand. 손을 따라 바람이 지나가고, 풀잎이 눕고 다시 일어서는 들판."
      >
        <canvas ref={canvasRef} className="sup-wind__canvas" aria-hidden="true" />
      </div>

      <p className="sup-wind__caption">
        Pass your hand across the field — the grass answers.{" "}
        <span lang="ko">
          손을 스치듯 움직여 보세요. 풀이 대답합니다. 손이 없어도 바람은
          스스로 다녀갑니다.
        </span>
      </p>
    </section>
  );
}

import { Gowun_Dodum, Instrument_Serif } from "next/font/google";

/**
 * The two voices of the forest:
 * Instrument Serif — the Latin display voice; the "SUP" wordmark, section
 * titles, and the italic asides that read like a guide speaking softly.
 * Gowun Dodum — every Hangul glyph and all body text; round, unhurried,
 * the voice that actually leads the breathing.
 *
 * styles.css consumes these as var(--font-instrument) / var(--font-gowun);
 * page.tsx applies the .variable classes on the entry root. The display
 * stack is `Instrument Serif, Gowun Dodum, serif`, so the giant 숲 falls
 * through the Latin face into Gowun Dodum with no extra markup.
 */
export const instrumentSerif = Instrument_Serif({
  weight: "400",
  style: ["normal", "italic"],
  subsets: ["latin"],
  variable: "--font-instrument",
  display: "swap",
});

export const gowunDodum = Gowun_Dodum({
  weight: "400",
  subsets: ["latin"],
  variable: "--font-gowun",
  display: "swap",
});

"use client";

import { useEffect, useRef } from "react";

/** How much of the plant grows on its own, before any scroll. */
const INTRO_REACH = 0.74;
/** How long the intro growth takes to get there. */
const INTRO_MS = 5200;
/** Scroll finishes the crown within the first ~0.85 viewport. */
const SCROLL_SPAN = 0.85;
/** Per-frame lerp toward the target, normalized to 60fps in the loop. */
const GROW_LERP = 0.06;

/**
 * Drives `--sup-grow` (0 → 1) on the referenced element — the L-system
 * plant's shared growth clock. Every branch in styles.css converts this one
 * variable into its own stroke-dashoffset window, and every leaf into an
 * opacity/scale window, so a single property write per frame grows the
 * whole plant in order, base first, crown last.
 *
 * The CSS fallback is `var(--sup-grow, 1)` — fully grown — so without
 * JavaScript, and under reduced motion (where this hook does nothing), the
 * plant simply stands complete. With motion allowed, growth eases to
 * INTRO_REACH on its own and scroll raises the rest; scrolling back lets
 * the crown recede a little, which is the point: the forest keeps your pace.
 *
 * The rAF loop only runs while the element is near the viewport and the
 * tab is visible.
 */
export function useGrowth<T extends HTMLElement>(disabled: boolean) {
  const ref = useRef<T | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el || disabled) return;

    el.style.setProperty("--sup-grow", "0");

    let raf = 0;
    let running = false;
    let inView = true;
    let value = 0;
    let last = 0;
    const born = performance.now();
    const easeOut = (u: number) => 1 - (1 - u) ** 3;

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      const dt = Math.min(now - last, 48);
      last = now;
      const intro =
        easeOut(Math.min((now - born) / INTRO_MS, 1)) * INTRO_REACH;
      const scroll = Math.min(
        window.scrollY / (window.innerHeight * SCROLL_SPAN),
        1,
      );
      const target = Math.min(1, intro + (1 - INTRO_REACH) * scroll);
      const next = value + (target - value) * GROW_LERP * (dt / 16.7);
      if (Math.abs(next - value) < 0.0002) return;
      value = next;
      el.style.setProperty("--sup-grow", value.toFixed(4));
    };

    const start = () => {
      if (running) return;
      running = true;
      last = performance.now();
      raf = requestAnimationFrame(step);
    };
    const stop = () => {
      running = false;
      cancelAnimationFrame(raf);
    };

    const io = new IntersectionObserver((hits) => {
      inView = hits[hits.length - 1].isIntersecting;
      if (inView && !document.hidden) start();
      else stop();
    });
    io.observe(el);

    const onVisibility = () => {
      if (document.hidden) stop();
      else if (inView) start();
    };
    document.addEventListener("visibilitychange", onVisibility);

    return () => {
      stop();
      io.disconnect();
      document.removeEventListener("visibilitychange", onVisibility);
      // hand the element back to the CSS fallback (fully grown)
      el.style.removeProperty("--sup-grow");
    };
  }, [disabled]);

  return ref;
}

"use client";

import { useEffect, useRef } from "react";

/** Per-frame lerp toward the pointer, normalized to 60fps in the loop. */
const DRIFT_LERP = 0.05;

/**
 * Drives `--sup-px` / `--sup-py` (each −1…1) on the referenced element —
 * the hero's parallax depth. styles.css multiplies these into small,
 * capped translations: the understory shrub drifts against the pointer,
 * the main tree with it, the copy barely at all. The lerp is slow enough
 * that the layers feel like they are settling, not tracking.
 *
 * Fine pointers only — on touch the layers simply rest (the growth and
 * sway animations carry the life instead), and under reduced motion this
 * hook does nothing; the CSS fallback for both variables is 0.
 */
export function usePointerDrift<T extends HTMLElement>(disabled: boolean) {
  const ref = useRef<T | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el || disabled) return;
    if (!window.matchMedia("(hover: hover) and (pointer: fine)").matches) {
      return;
    }

    let raf = 0;
    let running = false;
    let inView = true;
    let x = 0;
    let y = 0;
    let tx = 0;
    let ty = 0;
    let last = 0;

    const step = (now: number) => {
      raf = requestAnimationFrame(step);
      const dt = Math.min(now - last, 48);
      last = now;
      const k = DRIFT_LERP * (dt / 16.7);
      x += (tx - x) * k;
      y += (ty - y) * k;
      el.style.setProperty("--sup-px", x.toFixed(4));
      el.style.setProperty("--sup-py", y.toFixed(4));
    };

    const start = () => {
      if (running) return;
      running = true;
      last = performance.now();
      raf = requestAnimationFrame(step);
    };
    const stop = () => {
      running = false;
      cancelAnimationFrame(raf);
    };

    const onMove = (ev: PointerEvent) => {
      if (ev.pointerType !== "mouse" && ev.pointerType !== "pen") return;
      const r = el.getBoundingClientRect();
      tx = Math.max(-1, Math.min(1, ((ev.clientX - r.left) / r.width) * 2 - 1));
      ty = Math.max(-1, Math.min(1, ((ev.clientY - r.top) / r.height) * 2 - 1));
    };
    const onLeave = () => {
      tx = 0;
      ty = 0;
    };
    el.addEventListener("pointermove", onMove);
    el.addEventListener("pointerleave", onLeave);

    const io = new IntersectionObserver((hits) => {
      inView = hits[hits.length - 1].isIntersecting;
      if (inView && !document.hidden) start();
      else stop();
    });
    io.observe(el);

    const onVisibility = () => {
      if (document.hidden) stop();
      else if (inView) start();
    };
    document.addEventListener("visibilitychange", onVisibility);

    return () => {
      stop();
      io.disconnect();
      el.removeEventListener("pointermove", onMove);
      el.removeEventListener("pointerleave", onLeave);
      document.removeEventListener("visibilitychange", onVisibility);
      el.style.removeProperty("--sup-px");
      el.style.removeProperty("--sup-py");
    };
  }, [disabled]);

  return ref;
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-in` class. The pre-reveal state (opacity/translate) lives
 * in styles.css and is gated behind the `.sup-js` root class, so the content
 * is fully visible when JavaScript never runs.
 *
 * Elements that intersect in the same observer batch are staggered 110ms
 * apart via transition-delay — slower than most galleries on purpose; the
 * forest does not hurry.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-in");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          el.style.transitionDelay = `${batch * 110}ms`;
          el.classList.add("is-in");
          io.unobserve(el);
          batch += 1;
        }
      },
      { threshold: 0.12, rootMargin: "0px 0px -10% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

"use client";

import { useEffect, useRef } from "react";
import "./styles.css";
import { gowunDodum, instrumentSerif } from "./fonts";
import Hero from "./components/Hero";
import WindField from "./components/WindField";
import BreathingGuide from "./components/BreathingGuide";
import Retreats from "./components/Retreats";
import Footer from "./components/Footer";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";

/**
 * 숲 SUP — forest bathing retreats.
 * A Korean forest-bathing house below a birch ridge in Gangwon-do. The page
 * is the walk itself: an L-system tree draws itself in as you arrive, a
 * canvas meadow bends under the breeze your pointer makes, and a 4·4·4
 * breathing guide counts with you. Everything green is drawn by code —
 * there is not one raster image here.
 *
 * `.sup-js` is added on mount so every pre-reveal style is JS-gated — with
 * JavaScript disabled the full page (plants grown, meadow resting) is
 * simply visible.
 */
export default function SupPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const revealRef = useReveal<HTMLDivElement>(reduced);

  useEffect(() => {
    // Imperative on purpose: the class is a signal to CSS that JS is alive,
    // not React state — and it never changes once set.
    rootRef.current?.classList.add("sup-js");
    window.parent?.postMessage({ type: "oneshot:ready", slug: "sup" }, "*");
  }, []);

  return (
    <div
      id="sup-top"
      ref={rootRef}
      className={`${instrumentSerif.variable} ${gowunDodum.variable} sup-root`}
    >
      <div ref={revealRef} className="sup-ground">
        <Hero />
        <main>
          <WindField />
          <BreathingGuide />
          <Retreats />
        </main>
        <Footer />
      </div>
    </div>
  );
}

/* ==========================================================================
   숲 SUP — forest bathing retreats
   organic-nature · moss and loam on cream · light is the only texture
   Scoped by convention to .sup-root; classes prefixed sup-.
   ========================================================================== */

.sup-root {
  /* -- palette ------------------------------------------------------------ */
  --sup-moss: #4a5d3a;             /* accent, headings, focus ring — 6.2:1 on cream */
  --sup-loam: #2e2a24;             /* primary text — 12:1 on cream */
  --sup-cream: #f2efe6;            /* the clearing — background */
  --sup-lichen: #a8b89a;           /* decorative ONLY (1.8:1): leaves, rules, grass */
  --sup-sun: #e9dfa8;              /* sunlight washes at low alpha — decorative */
  --sup-bark: rgba(46, 42, 36, 0.72);  /* ≈ #65615a — secondary text, 5.4:1 */
  --sup-moss-soft: #6f8457;        /* decorative mid-green: leaves, twig tips */
  --sup-hairline: rgba(74, 93, 58, 0.25); /* rules, borders */
  --sup-field: #e7ead6;            /* the meadow floor the grass stands on */

  /* -- procedurally consumed (canvas + SVG read these) --------------------- */
  --sup-trunk: #56523d;            /* branch tier 0 — bark */
  --sup-stem: #5c7245;             /* branch tier 2 */
  --sup-under-stem: #8d9d7d;       /* understory shrub stems */
  --sup-under-leaf: #b7c2a8;       /* understory shrub leaves */
  --sup-grass-lit: #c9d2ab;        /* backlit blades */
  --sup-grass-back: #a8b89a;       /* far row (lichen) */
  --sup-grass-mid: #7d9465;        /* middle row */
  --sup-grass-front: #55693f;      /* near row */
  --sup-pollen: #d9cd8f;           /* drifting motes */

  /* -- type ---------------------------------------------------------------- */
  --sup-font-display: var(--font-instrument), "Instrument Serif", "Gowun Dodum", serif;
  --sup-font-body: var(--font-gowun), "Gowun Dodum", "Apple SD Gothic Neo", sans-serif;

  /* -- motion ---------------------------------------------------------------
     ease-forest: fast to move, very long to settle — nothing here snaps. */
  --sup-ease: cubic-bezier(0.22, 0.8, 0.24, 1);

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--sup-cream);
  color: var(--sup-loam);
  font-family: var(--sup-font-body);
  font-size: clamp(16px, 0.4vw + 14px, 18px);
  line-height: 1.75;
  overflow-x: hidden;
  overflow-x: clip;
}

.sup-root,
.sup-root *,
.sup-root *::before,
.sup-root *::after {
  box-sizing: border-box;
}

.sup-root h1,
.sup-root h2,
.sup-root h3,
.sup-root p,
.sup-root ul {
  margin: 0;
}

.sup-root ul {
  padding: 0;
  list-style: none;
}

/* Korean is first-class: Gowun Dodum, its own rhythm, no orphan-broken words */
.sup-root :lang(ko) {
  font-family: var(--sup-font-body);
  word-break: keep-all;
  line-height: 1.8;
}

/* The guide's italic asides speak Instrument Serif */
.sup-root em {
  font-family: var(--sup-font-display);
  font-style: italic;
  letter-spacing: 0.01em;
}

/* Moss selection, scoped to the entry root */
.sup-root ::selection {
  background: var(--sup-moss);
  color: var(--sup-cream);
}

/* Keyboard focus: a moss ring with a soft canopy halo */
.sup-root :focus-visible {
  outline: 2px solid var(--sup-moss);
  outline-offset: 3px;
  border-radius: 3px;
  box-shadow: 0 0 0 6px rgba(74, 93, 58, 0.16);
}

.sup-link {
  color: var(--sup-moss);
  text-decoration: underline;
  text-decoration-color: var(--sup-hairline);
  text-decoration-thickness: 1px;
  text-underline-offset: 4px;
}

.sup-link:hover {
  text-decoration-color: var(--sup-moss);
}

.sup-ground {
  position: relative;
}

/* ==========================================================================
   Scroll reveals — pre-reveal state exists only when JS is alive
   ========================================================================== */

.sup-js [data-reveal] {
  opacity: 0;
  transform: translateY(20px);
}

.sup-js [data-reveal].is-in {
  opacity: 1;
  transform: translateY(0);
  transition:
    opacity 950ms var(--sup-ease),
    transform 950ms var(--sup-ease);
}

/* ==========================================================================
   Section heads — a Korean numeral, a title, a long hairline
   ========================================================================== */

.sup-sec {
  display: flex;
  align-items: baseline;
  gap: 1.1rem;
  margin-bottom: clamp(1.6rem, 4vh, 2.8rem);
}

.sup-sec__no {
  flex: none;
  font-size: 0.82rem;
  color: var(--sup-moss);
  letter-spacing: 0.24em;
}

.sup-sec__title {
  font-family: var(--sup-font-display);
  font-weight: 400;
  font-size: clamp(1.7rem, 3.4vw, 2.4rem);
  line-height: 1.15;
  letter-spacing: 0.01em;
  color: var(--sup-loam);
}

.sup-sec__ko {
  font-size: 0.62em;
  color: var(--sup-bark);
  margin-left: 0.35em;
}

.sup-sec::after {
  content: "";
  flex: 1;
  align-self: center;
  height: 1px;
  background: var(--sup-hairline);
  margin-left: 0.6rem;
}

/* ==========================================================================
   Hero — the arrival; an L-system tree draws itself in
   ========================================================================== */

.sup-hero {
  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: center;
  min-height: 100vh;
  min-height: 100svh;
  max-width: 1280px;
  margin-inline: auto;
  padding: clamp(24px, 6vw, 72px);
}

/* morning light from the upper left; it breathes very slowly */
.sup-hero__sun {
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: radial-gradient(
    110% 85% at 22% 0%,
    rgba(233, 223, 168, 0.5),
    rgba(233, 223, 168, 0.12) 45%,
    transparent 70%
  );
}

.sup-js .sup-hero__sun {
  animation: sup-sunbreathe 17s ease-in-out infinite alternate;
}

@keyframes sup-sunbreathe {
  from {
    opacity: 0.65;
  }
  to {
    opacity: 1;
  }
}

.sup-hero__stage {
  position: absolute;
  right: clamp(-40px, 1vw, 48px);
  bottom: 0;
  width: clamp(300px, 44vw, 640px);
  height: min(92%, 88vh);
  pointer-events: none;
}

.sup-hero__plant {
  position: absolute;
  bottom: 0;
  width: 100%;
  height: 100%;
}

.sup-hero__plant--back {
  right: 34%;
  transform: translate3d(
    calc(var(--sup-px, 0) * -7px),
    calc(var(--sup-py, 0) * -4px),
    0
  );
  opacity: 0.55;
}

.sup-hero__plant--main {
  right: 0;
  transform: translate3d(
    calc(var(--sup-px, 0) * 12px),
    calc(var(--sup-py, 0) * 7px),
    0
  );
}

/* -- the growth clock ------------------------------------------------------
   One variable, --sup-grow (0 → 1, fallback 1 = fully grown), is converted
   per branch into a stroke-dashoffset window [t0, t1] and per leaf into an
   opacity/scale window. Without JS or under reduced motion nothing is ever
   hidden: the fallback keeps every offset at 0 and every leaf at 1. */

.sup-growth path {
  fill: none;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.sup-growth__branch {
  stroke-dasharray: 1 1;
  stroke-dashoffset: clamp(
    0,
    calc((var(--t1) - var(--sup-grow, 1)) / var(--tw)),
    1.02
  );
}

.sup-growth__branch--t0 {
  stroke: var(--sup-trunk);
}
.sup-growth__branch--t1 {
  stroke: var(--sup-moss);
}
.sup-growth__branch--t2 {
  stroke: var(--sup-stem);
}
.sup-growth__branch--t3 {
  stroke: var(--sup-moss-soft);
}

.sup-growth__leaf {
  --sup-unfurl: clamp(0, calc((var(--sup-grow, 1) - var(--lt)) * 12), 1);
  opacity: var(--sup-unfurl);
  transform: scale(var(--sup-unfurl));
  transform-box: fill-box;
  transform-origin: left center;
  stroke: none;
}

.sup-growth__leaf--0 {
  fill: var(--sup-lichen);
}
.sup-growth__leaf--1 {
  fill: var(--sup-moss-soft);
}

.sup-hero__plant--back .sup-growth__branch {
  stroke: var(--sup-under-stem);
}
.sup-hero__plant--back .sup-growth__leaf {
  fill: var(--sup-under-leaf);
}

/* idle sway — mutually prime periods so the pair never visibly loops */
.sup-js .sup-hero__plant--main .sup-growth {
  transform-box: view-box;
  transform-origin: 50% 100%;
  animation: sup-sway 9.4s ease-in-out infinite alternate;
}

.sup-js .sup-hero__plant--back .sup-growth {
  transform-box: view-box;
  transform-origin: 50% 100%;
  animation: sup-sway 12.7s ease-in-out infinite alternate-reverse;
}

@keyframes sup-sway {
  from {
    transform: rotate(-0.5deg);
  }
  to {
    transform: rotate(0.5deg);
  }
}

.sup-hero__copy {
  position: relative;
  max-width: 34rem;
  transform: translate3d(
    calc(var(--sup-px, 0) * -4px),
    calc(var(--sup-py, 0) * -2px),
    0
  );
}

.sup-hero__kicker {
  font-size: 0.78rem;
  letter-spacing: 0.34em;
  color: var(--sup-moss);
  margin-bottom: clamp(1rem, 3vh, 2rem);
}

.sup-hero__title {
  display: flex;
  align-items: baseline;
  gap: 0.18em;
  font-weight: 400;
  line-height: 0.94;
  margin-bottom: clamp(1.2rem, 3.5vh, 2.2rem);
}

.sup-hero__hangul {
  font-family: var(--sup-font-body);
  font-size: clamp(6.4rem, 21vw, 13.5rem);
  color: var(--sup-loam);
  letter-spacing: -0.02em;
}

.sup-hero__latin {
  display: flex;
  flex-direction: column;
  gap: 0.4em;
  font-family: var(--sup-font-display);
  font-size: clamp(1.7rem, 4.6vw, 3rem);
  color: var(--sup-moss);
  letter-spacing: 0.22em;
}

.sup-hero__latin-sub {
  font-style: italic;
  font-size: 0.44em;
  letter-spacing: 0.05em;
  color: var(--sup-bark);
}

.sup-hero__lede {
  max-width: 26rem;
  margin-bottom: clamp(1.6rem, 4vh, 2.6rem);
}

.sup-hero__lede em {
  display: block;
  font-size: 1.18rem;
  line-height: 1.5;
  margin-bottom: 0.5rem;
}

.sup-hero__lede span {
  display: block;
  color: var(--sup-bark);
  font-size: 0.95rem;
}

.sup-hero__cta {
  display: inline-block;
  padding: 0.72em 1.6em;
  border: 1px solid var(--sup-moss);
  border-radius: 999px;
  color: var(--sup-moss);
  text-decoration: none;
  font-size: 0.92rem;
  letter-spacing: 0.04em;
}

/* states snap — only entrances are eased on this page */
.sup-hero__cta:hover {
  background: var(--sup-moss);
  color: var(--sup-cream);
}

.sup-hero__hint {
  position: absolute;
  left: 50%;
  bottom: clamp(14px, 3vh, 30px);
  transform: translateX(-50%);
  font-size: 0.8rem;
  color: var(--sup-bark);
  letter-spacing: 0.06em;
  white-space: nowrap;
}

/* ==========================================================================
   하나 · The wind field — canvas meadow
   ========================================================================== */

.sup-wind {
  max-width: 1160px;
  margin-inline: auto;
  padding: clamp(72px, 12vh, 150px) clamp(20px, 5vw, 56px) 0;
}

.sup-wind__lede {
  max-width: 36rem;
  margin-bottom: clamp(2rem, 5vh, 3.4rem);
}

.sup-wind__lede em {
  font-size: 1.35rem;
  color: var(--sup-loam);
}

.sup-wind__lede span {
  display: block;
  margin-top: 0.4rem;
  color: var(--sup-bark);
  font-size: 0.95rem;
}

/* full-bleed stage; the grass runs past the reading column on purpose */
.sup-wind__stage {
  position: relative;
  height: clamp(380px, 62vh, 560px);
  margin-inline: calc(50% - 50vw);
  border-top: 1px solid var(--sup-hairline);
  border-bottom: 1px solid var(--sup-hairline);
  background: linear-gradient(
    180deg,
    var(--sup-cream) 0%,
    rgba(233, 223, 168, 0.28) 46%,
    var(--sup-field) 100%
  );
}

.sup-wind__canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  display: block;
}

.sup-wind__caption {
  max-width: 34rem;
  margin-inline: auto;
  padding-top: 1.4rem;
  text-align: center;
  font-size: 0.88rem;
  color: var(--sup-bark);
}

.sup-wind__caption span {
  display: block;
  margin-top: 0.2rem;
}

/* ==========================================================================
   둘 · One breath — the 4·4·4 guide
   ========================================================================== */

.sup-breath {
  max-width: 880px;
  margin-inline: auto;
  padding: clamp(72px, 12vh, 150px) clamp(20px, 5vw, 56px);
  text-align: center;
}

.sup-breath .sup-sec {
  text-align: left;
}

.sup-breath__how {
  max-width: 34rem;
  margin-inline: auto;
  margin-bottom: clamp(2rem, 6vh, 3.6rem);
}

.sup-breath__how em {
  display: block;
  font-size: 1.3rem;
  line-height: 1.5;
  margin-bottom: 0.5rem;
}

.sup-breath__how span {
  display: block;
  color: var(--sup-bark);
  font-size: 0.95rem;
}

.sup-breath__stage {
  position: relative;
  display: grid;
  place-items: center;
  height: clamp(300px, 46vh, 420px);
  margin-bottom: 1.8rem;
}

/* the orb — scale is the only thing that moves, and the fallback (0.62,
   a resting mid-breath) is what no-JS and reduced motion see */
.sup-breath__orb {
  grid-area: 1 / 1;
  width: clamp(190px, 30vw, 270px);
  aspect-ratio: 1;
  border-radius: 50%;
  background: radial-gradient(
    circle at 38% 30%,
    rgba(233, 223, 168, 0.75),
    rgba(168, 184, 154, 0.62) 52%,
    rgba(111, 132, 87, 0.55) 100%
  );
  transform: scale(calc(0.76 + 0.3 * var(--sup-breath, 0.62)));
  will-change: transform;
}

.sup-breath__halo {
  grid-area: 1 / 1;
  width: clamp(190px, 30vw, 270px);
  aspect-ratio: 1;
  border-radius: 50%;
  border: 1px solid var(--sup-moss);
  opacity: calc(0.22 + 0.4 * var(--sup-breath, 0.62));
  transform: scale(calc(0.94 + 0.36 * var(--sup-breath, 0.62)));
  will-change: transform, opacity;
}

.sup-breath__readout {
  grid-area: 1 / 1;
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.1rem;
}

.sup-breath__word {
  font-size: 1.5rem;
  color: var(--sup-loam);
}

.sup-breath__word-en {
  font-family: var(--sup-font-display);
  font-style: italic;
  font-size: 1rem;
  color: var(--sup-loam);
}

.sup-breath__count {
  font-family: var(--sup-font-display);
  font-size: 2.1rem;
  line-height: 1.1;
  color: var(--sup-moss);
  font-variant-numeric: tabular-nums;
}

.sup-breath__toggle {
  font: inherit;
  font-size: 0.92rem;
  letter-spacing: 0.04em;
  color: var(--sup-moss);
  background: transparent;
  border: 1px solid var(--sup-moss);
  border-radius: 999px;
  padding: 0.72em 1.6em;
  cursor: pointer;
}

.sup-breath__toggle:hover {
  background: var(--sup-moss);
  color: var(--sup-cream);
}

.sup-breath__note {
  margin-top: 2.2rem;
  font-size: 0.95rem;
  color: var(--sup-bark);
}

.sup-breath__note em {
  color: var(--sup-loam);
  font-size: 1.05rem;
  margin-right: 0.4em;
}

/* ==========================================================================
   셋 · The retreats — a quiet ledger
   ========================================================================== */

.sup-retreats {
  max-width: 880px;
  margin-inline: auto;
  padding: clamp(72px, 12vh, 150px) clamp(20px, 5vw, 56px);
}

.sup-retreats__lede {
  max-width: 36rem;
  margin-bottom: clamp(2.4rem, 6vh, 4rem);
}

.sup-retreats__lede em {
  font-size: 1.35rem;
  color: var(--sup-loam);
}

.sup-retreats__lede span {
  display: block;
  margin-top: 0.4rem;
  color: var(--sup-bark);
  font-size: 0.95rem;
}

.sup-retreat {
  display: grid;
  grid-template-columns: 7.5rem 1fr;
  grid-template-areas:
    "when name"
    "when sense";
  column-gap: 1.6rem;
  row-gap: 0.5rem;
  padding-block: clamp(1.6rem, 4vh, 2.4rem);
  border-top: 1px solid var(--sup-hairline);
}

.sup-retreat:last-child {
  border-bottom: 1px solid var(--sup-hairline);
}

.sup-retreat__when {
  grid-area: when;
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.sup-retreat__time {
  font-family: var(--sup-font-display);
  font-size: 1.5rem;
  color: var(--sup-moss);
  font-variant-numeric: tabular-nums;
}

.sup-retreat__length {
  font-size: 0.8rem;
  color: var(--sup-bark);
  letter-spacing: 0.05em;
}

.sup-retreat__name {
  grid-area: name;
  font-weight: 400;
  display: flex;
  align-items: baseline;
  gap: 0.7em;
  flex-wrap: wrap;
}

.sup-retreat__ko {
  font-size: 1.45rem;
  color: var(--sup-loam);
}

.sup-retreat__en {
  font-family: var(--sup-font-display);
  font-style: italic;
  font-size: 1.05rem;
  color: var(--sup-bark);
}

.sup-retreat__sense {
  grid-area: sense;
  max-width: 34rem;
}

.sup-retreat__sense em {
  display: block;
  font-size: 1.02rem;
  color: var(--sup-loam);
  margin-bottom: 0.2rem;
}

.sup-retreat__sense span {
  display: block;
  font-size: 0.92rem;
  color: var(--sup-bark);
}

/* ==========================================================================
   Footer — the clearing at the end
   ========================================================================== */

.sup-footer {
  max-width: 880px;
  margin-inline: auto;
  padding: clamp(72px, 12vh, 140px) clamp(20px, 5vw, 56px) clamp(48px, 8vh, 80px);
  text-align: center;
  border-top: 1px solid var(--sup-hairline);
}

.sup-footer__call {
  font-family: var(--sup-font-display);
  font-size: clamp(1.7rem, 4.4vw, 2.7rem);
  letter-spacing: 0.14em;
  color: var(--sup-loam);
  margin-bottom: clamp(1.6rem, 4vh, 2.6rem);
}

.sup-footer__call :lang(ko) {
  letter-spacing: 0.08em;
}

.sup-footer__dot {
  color: var(--sup-moss);
}

.sup-footer__where {
  margin-bottom: 2rem;
  color: var(--sup-bark);
  font-size: 0.95rem;
}

.sup-footer__where-en {
  display: block;
  font-family: var(--sup-font-display);
  font-style: italic;
}

.sup-footer__coords {
  margin-top: 0.5rem;
  font-size: 0.8rem;
  letter-spacing: 0.14em;
  color: var(--sup-lichen);
}

.sup-footer__contact {
  display: flex;
  justify-content: center;
  gap: 2.2rem;
  flex-wrap: wrap;
  margin-bottom: 2.6rem;
  font-size: 0.92rem;
}

.sup-footer__legal {
  font-size: 0.85rem;
  color: var(--sup-bark);
}

/* ==========================================================================
   Composition — small clearings
   ========================================================================== */

@media (max-width: 900px) {
  .sup-hero__stage {
    right: -14%;
    width: clamp(300px, 72vw, 460px);
    opacity: 0.5;
  }

  .sup-hero__copy {
    max-width: 30rem;
  }

  .sup-retreat {
    grid-template-columns: 1fr;
    grid-template-areas:
      "when"
      "name"
      "sense";
    row-gap: 0.4rem;
  }

  .sup-retreat__when {
    flex-direction: row;
    align-items: baseline;
    gap: 0.8rem;
  }
}

@media (max-width: 480px) {
  .sup-sec {
    gap: 0.7rem;
  }

  .sup-hero__hint {
    font-size: 0.72rem;
  }

  .sup-footer__contact {
    flex-direction: column;
    gap: 0.9rem;
    align-items: center;
  }
}

/* ==========================================================================
   Reduced motion — the forest, already still.
   The plants stand fully grown (the --sup-grow fallback is 1 and the hooks
   never run), the meadow is one composed frame, the orb rests mid-breath,
   and the written instruction carries the whole exercise.
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .sup-js .sup-hero__sun,
  .sup-js .sup-hero__plant--main .sup-growth,
  .sup-js .sup-hero__plant--back .sup-growth {
    animation: none;
  }

  .sup-hero__plant--back,
  .sup-hero__plant--main,
  .sup-hero__copy {
    transform: none;
  }

  .sup-js [data-reveal] {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .sup-breath__orb {
    transform: scale(0.9);
  }

  .sup-breath__halo {
    transform: scale(1.04);
    opacity: 0.4;
  }
}
